#include <bits/stdc++.h>
using namespace std;

long long largestRectangle(vector<int>& heights) {
    stack<int> stack;
    stack.push(-1);
    int max_area = 0;

    for (int i = 0; i < heights.size(); i++) {
        while (stack.top() != -1 && heights[i] <= heights[stack.top()]) {
            int height = heights[stack.top()];
            stack.pop();
            int width = i - stack.top() - 1;
            max_area = max(max_area, height * width);
        }
        stack.push(i);
    }

    while (stack.top() != -1) {
        int height = heights[stack.top()];
        stack.pop();
        int width = heights.size() - stack.top() - 1;
        max_area = max(max_area, height * width);
    }

    return max_area;
}

int main() {
    int t;
    cin >> t;

    while(t--) {
        int n;
        cin >> n;

        vector<int> heights(n);
        for(int i = 0; i < n; i++) {
            cin >> heights[i];
        }

        cout << largestRectangle(heights) << endl;
    }

    return 0;
}
